// Account class
class Account {
  private balance: number
  private events: AccountEvent[] = []
  private accountId: string

  constructor(accountId: string, initialBalance: number = 0) {
    if (initialBalance < 0) {
      throw new Error("Initial balance cannot be negative")
    }
    this.accountId = accountId
    this.balance = initialBalance
  }

  getBalance(): number {
    return this.balance
  }

  deposit(amount: number): void {
    if (amount <= 0) {
      throw new Error("Deposit amount must be positive")
    }
    const event: DepositEvent = {
      type: 'Deposited',
      amount,
      timestamp: Date.now()
    }
    this.applyEvent(event)
    this.events.push(event)
  }

  withdraw(amount: number): void {
    if (amount <= 0) {
      throw new Error("Withdrawal amount must be positive")
    }
    if (amount > this.balance) {
      throw new Error("Insufficient funds")
    }
    const event: WithdrawnEvent = {
      type: 'Withdrawn',
      amount,
      timestamp: Date.now()
    }
    this.applyEvent(event)
    this.events.push(event)
  }

  transfer(amount: number, to: string): void {
    if (amount <= 0) {
      throw new Error("Transfer amount must be positive")
    }
    if (amount > this.balance) {
      throw new Error("Insufficient funds for transfer")
    }
    const event: TransferredEvent = {
      type: 'Transferred',
      amount,
      to,
      timestamp: Date.now()
    }
    this.applyEvent(event)
    this.events.push(event)
  }

  private applyEvent(event: AccountEvent): void {
    switch (event.type) {
      case 'Deposited':
        this.balance += event.amount
        break
      case 'Withdrawn':
        this.balance -= event.amount
        break
      case 'Transferred':
        this.balance -= event.amount
        break
    }
  }

  getEvents(): AccountEvent[] {
    return [...this.events]
  }
}

export function createAccountFromEvents(accountId: string, events: AccountEvent[]): Account {
  const account = new Account(accountId, 0)
  for (const event of events) {
    account['applyEvent'](event)
    account['events'].push(event)
  }
  return account
}
